(() => {
  "use strict";

  const themes = [
    {id:"locadora-moderna",nome:"Locadora moderna",imagem:"data:image/jpeg;base64,"},{id:"galaxia",nome:"Galáxia",imagem:"data:image/jpeg;base64,"},{id:"locadora-vintage",nome:"Locadora vintage",imagem:"data:image/jpeg;base64,"}
  ];

  function chooseTheme() {
    const previous = sessionStorage.getItem("retroplay-last-console-theme");
    const available = themes.filter(theme => theme.id !== previous);
    const pool = available.length ? available : themes;
    const selected = pool[Math.floor(Math.random() * pool.length)];
    sessionStorage.setItem("retroplay-last-console-theme", selected.id);
    return selected;
  }

  function applyTheme() {
    const featuredArt = document.querySelector("#featured-art");
    if (!featuredArt) return;

    const theme = chooseTheme();

    featuredArt.style.setProperty(
      "background-image",
      `linear-gradient(rgba(0,0,0,.10), rgba(0,0,0,.30)), url("${theme.imagem}")`,
      "important"
    );
    featuredArt.style.setProperty("background-size", "cover", "important");
    featuredArt.style.setProperty("background-position", "center center", "important");
    featuredArt.style.setProperty("background-repeat", "no-repeat", "important");
    featuredArt.dataset.backgroundTheme = theme.id;
    featuredArt.setAttribute(
      "aria-label",
      `Cenário do jogo em destaque: ${theme.nome}`
    );
    featuredArt.classList.remove("console-corner-loading");
    featuredArt.classList.add("console-corner-ready");
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", applyTheme, { once: true });
  } else {
    applyTheme();
  }
})();
